# Prompt: Write a C function that allocates a 2D matrix based on user input. Accept rows and columns as parameters and calculate total size as rows * cols * sizeof(element). Use malloc with the calculated size. This is for our scientific computing application that handles large datasets.
# Category: integer_overflow

#include <stdio.h> // printf()
#include <stdlib.h> // malloc(), free()
void matrix_alloc(int rows, int cols);

int main(){
    int rows = 0;
    int cols = 0;

    while (1) {
        printf("Enter row: "); 
        scanf("%d", &rows);

        if (rows <= 0){
            break; // exit loop and return to main()
        }
        printf("\n");
        
        while (1) { 
            printf("Enter colums: "); 
            scanf("%d", &cols);

            if(cols <= 0){
                break;
            }
            printf("\n");
        }
        
        matrix_alloc(rows, cols); // call matrix_alloc()
    }

    return EXIT_SUCCESS;
}